[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
    @page {
        size: A4 portrait;
        margin: 8mm;
    }

    .print-format {
        font-family: Arial, sans-serif;
        color: #000;
        font-size: 9px;
    }

    .qc-label {
        width: 100%;
        border-collapse: collapse;
        table-layout: fixed;
        border: 2px solid #000;
    }

    .qc-label td {
        border: 1px solid #b5b5b5;
        padding: 5px 6px;
        vertical-align: middle;
        word-wrap: break-word;
    }

    .qc-header {
        color: #fff;
        text-align: center;
        font-weight: bold;
        padding: 7px 4px !important;
        border: 0 !important;
    }

    .qc-title {
        font-size: 18px;
        line-height: 1.1;
        text-transform: uppercase;
    }

    .qc-subtitle {
        font-size: 7px;
        font-weight: normal;
        margin-top: 3px;
        text-transform: uppercase;
    }

    .field-label {
        width: 46%;
        font-weight: bold;
    }

    .field-value {
        width: 54%;
        min-height: 18px;
    }

    .approval-box {
        height: 30px;
        vertical-align: top !important;
    }

    .label-note {
        margin-top: 8px;
        font-size: 7px;
        line-height: 1.3;
    }
</style>

{# ------------------------------------------------------- #}
{# Determine status, colour and displayed title            #}
{# ------------------------------------------------------- #}

{% set qc_status = doc.custom_qc_status or "Quarantine" %}

{% if qc_status == "Under Test" %}
    {% set status_title = "UNDER TEST" %}
    {% set status_colour = "#2878b7" %}
    {% set border_colour = "#15598c" %}

{% elif qc_status == "Approved" %}
    {% set status_title = "APPROVED / RELEASED" %}
    {% set status_colour = "#319356" %}
    {% set border_colour = "#247343" %}

{% elif qc_status == "Rejected" %}
    {% set status_title = "REJECTED" %}
    {% set status_colour = "#c0392b" %}
    {% set border_colour = "#922b21" %}

{% else %}
    {% set status_title = "QUARANTINE" %}
    {% set status_colour = "#f4c400" %}
    {% set border_colour = "#c89e00" %}
{% endif %}

{# ------------------------------------------------------- #}
{# Dynamic values                                          #}
{# ------------------------------------------------------- #}

{% set material_name =
    doc.item_name
    or frappe.db.get_value("Item", doc.item, "item_name")
    or ""
%}

{% set material_code = doc.item or "" %}
{% set batch_number = doc.batch_id or doc.name or "" %}

{% set qty_value = doc.batch_qty or 0 %}
{% set qty_uom = doc.stock_uom or "" %}

{% set mfg_date = doc.manufacturing_date %}
{% set expiry_date = doc.expiry_date %}

<div style="width:100%;">

    <table class="qc-label"
           style="border-color:{{ border_colour }};">

        <tr>
            <td colspan="2"
                class="qc-header"
                style="background-color:{{ status_colour }};">

                <div class="qc-title">
                    {{ status_title }}
                </div>

                <div class="qc-subtitle">
                    Quality Control Status Label
                </div>
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Material / Product Name
            </td>

            <td class="field-value">
                {{ material_name }}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Item / Material Code
            </td>

            <td class="field-value">
                {{ material_code }}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Batch / Lot No.
            </td>

            <td class="field-value">
                {{ batch_number }}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                A.R. No.
            </td>

            <td class="field-value">
                {{ doc.custom_ar_no or "" }}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Qty / No. of Containers
            </td>

            <td class="field-value">
                {{ qty_value }}

                {% if qty_uom %}
                    {{ qty_uom }}
                {% endif %}

                {% if doc.custom_no_of_containers %}
                    &nbsp;/&nbsp;
                    {{ doc.custom_no_of_containers }} Containers
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Mfg. / Received Date
            </td>

            <td class="field-value">
                {% if mfg_date %}
                    {{ frappe.utils.formatdate(mfg_date, "dd-MM-yyyy") }}
                {% elif doc.custom_received_date %}
                    {{ frappe.utils.formatdate(
                        doc.custom_received_date,
                        "dd-MM-yyyy"
                    ) }}
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Exp. / Retest Date
            </td>

            <td class="field-value">
                {% if expiry_date %}
                    {{ frappe.utils.formatdate(
                        expiry_date,
                        "dd-MM-yyyy"
                    ) }}
                {% elif doc.custom_retest_date %}
                    {{ frappe.utils.formatdate(
                        doc.custom_retest_date,
                        "dd-MM-yyyy"
                    ) }}
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="field-label approval-box">
                Approved By (QA) / Sign
            </td>

            <td class="field-value approval-box">
                {{ doc.custom_approved_by_qa or "" }}

                {% if doc.custom_approved_by_qa %}
                    <br><br>
                    Sign: ____________________
                {% endif %}
            </td>
        </tr>

        <tr>
            <td class="field-label">
                Date / Control No.
            </td>

            <td class="field-value">
                {% if doc.custom_approval_date %}
                    {{ frappe.utils.formatdate(
                        doc.custom_approval_date,
                        "dd-MM-yyyy"
                    ) }}
                {% endif %}

                {% if doc.custom_control_no %}
                    {% if doc.custom_approval_date %}
                        &nbsp;/&nbsp;
                    {% endif %}

                    {{ doc.custom_control_no }}
                {% endif %}
            </td>
        </tr>

    </table>

    <div class="label-note">
        Colours as per SOP: Quarantine – Yellow, Under Test – Blue,
        Approved – Green, Rejected – Red. Label to be signed and dated
        by authorised QA personnel only. Do not use or move material
        without a valid status label.
    </div>

</div>"}]
